// Example: Kafka producer tuning for high throughput
Properties props = new Properties();
props.put("bootstrap.servers", "kafka:9092");
props.put("acks", "all");
props.put("compression.type", "snappy");
props.put("linger.ms", "50");        // wait to batch
props.put("batch.size", Integer.toString(64*1024)); // 64KB
props.put("buffer.memory", Long.toString(512*1024*1024L));
Producer<String, String> p = new KafkaProducer<>(props, new StringSerializer(), new StringSerializer());
for (int i=0;i<1000000;i++) {
  p.send(new ProducerRecord<>("events", Integer.toString(i%1000), "message-"+i));
}
p.flush();
p.close();
```

